text:
Interactive Tool: Mean, Median, and Standard Deviation Explorer

Use this tool to visualize how mean, median, and standard deviation behave for different distributions. Choose a distribution, adjust its parameters, and run experiments to compare theoretical values with observed results from random samples.

html`&lt;style&gt;
.stats-tool {
  border: 2px solid #ddd; border-radius: 8px; padding: 20px; margin: 1em 0; background: #fafafa;
  font-family: 'PT Sans', sans-serif;
}
.stats-tool .row { display: flex; flex-wrap: wrap; gap: 16px; align-items: center; margin-bottom: 12px; }
.stats-tool label { font-weight: 600; margin-right: 4px; }
.stats-tool select, .stats-tool input[type="number"] {
  padding: 5px 10px; border: 1px solid #ccc; border-radius: 4px; font-size: 0.95em;
}
.stats-tool input[type="number"] { width: 130px; }
.stats-tool .btn-row { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; margin-top: 10px; }
.stats-tool button {
  padding: 7px 16px; border: 1px solid #22176F; background: #fff; color: #22176F;
  border-radius: 4px; font-size: 0.9em; font-weight: 600; cursor: pointer;
}
.stats-tool button:hover { background: #22176F; color: #fff; }
.stats-tool .stats-table { margin-top: 10px; font-size: 0.9em; }
.stats-tool .stats-table td { padding: 2px 12px; }
.stats-tool .stats-table .theo { color: #4682B4; font-weight: 700; }
.stats-tool .stats-table .obs { color: #CC7000; font-weight: 700; }
&lt;/style&gt;`







{
  const Plot = await import("https://esm.sh/@observablehq/plot@0.6");
  let experiments = [];

  const container = html`&lt;div class="stats-tool"&gt;
    &lt;div class="row"&gt;
      &lt;div&gt;&lt;label&gt;Distribution:&lt;/label&gt;
        &lt;select id="st-dist"&gt;
          &lt;option value="dice"&gt;Discrete - Roll a die&lt;/option&gt;
          &lt;option value="binomial"&gt;Discrete - Binomial&lt;/option&gt;
          &lt;option value="normal"&gt;Continuous - Normal&lt;/option&gt;
          &lt;option value="chisq"&gt;Continuous - Chi-squared&lt;/option&gt;
        &lt;/select&gt;
      &lt;/div&gt;
      &lt;div id="st-params"&gt;&lt;/div&gt;
    &lt;/div&gt;
    &lt;div id="st-chart" style="min-height:300px;"&gt;&lt;/div&gt;
    &lt;div id="st-stats-display" class="stats-table"&gt;&lt;/div&gt;
    &lt;div class="btn-row"&gt;
      &lt;strong&gt;Run the experiment:&lt;/strong&gt;
      &lt;button id="st-1"&gt;one time&lt;/button&gt;
      &lt;button id="st-10"&gt;10 times&lt;/button&gt;
      &lt;button id="st-50"&gt;50 times&lt;/button&gt;
      &lt;button id="st-100"&gt;100 times&lt;/button&gt;
      &lt;button id="st-refresh"&gt;Refresh&lt;/button&gt;
    &lt;/div&gt;
    &lt;div id="st-info" style="font-size:0.85em;color:#666;margin-top:8px;"&gt;&lt;/div&gt;
  &lt;/div&gt;`;

  const distEl = container.querySelector('#st-dist');
  const paramsEl = container.querySelector('#st-params');
  const chartEl = container.querySelector('#st-chart');
  const statsEl = container.querySelector('#st-stats-display');
  const infoEl = container.querySelector('#st-info');

  function getParams() {
    const d = distEl.value;
    if (d === "dice") return {dist: d};
    if (d === "binomial") return {dist: d, n: parseInt(container.querySelector('#st-n')?.value || 10), p: parseFloat(container.querySelector('#st-p')?.value || 0.5)};
    if (d === "normal") return {dist: d, mu: parseFloat(container.querySelector('#st-mu')?.value || 0), sigma: parseFloat(container.querySelector('#st-sigma')?.value || 1)};
    return {dist: d, k: parseInt(container.querySelector('#st-k')?.value || 2)};
  }

  function updateParamsUI() {
    const d = distEl.value;
    if (d === "dice") paramsEl.innerHTML = '';
    else if (d === "binomial") paramsEl.innerHTML = `&lt;label&gt;n =&lt;/label&gt;&lt;input type="number" id="st-n" value="10" min="1" max="50"&gt; &lt;label style="margin-left:12px;"&gt;p =&lt;/label&gt;&lt;input type="number" id="st-p" value="0.5" min="0.01" max="0.99" step="0.05"&gt;`;
    else if (d === "normal") paramsEl.innerHTML = `&lt;label&gt;μ =&lt;/label&gt;&lt;input type="number" id="st-mu" value="0" step="0.5"&gt; &lt;label style="margin-left:12px;"&gt;σ =&lt;/label&gt;&lt;input type="number" id="st-sigma" value="1" min="0.1" step="0.1"&gt;`;
    else paramsEl.innerHTML = `&lt;label&gt;k =&lt;/label&gt;&lt;input type="number" id="st-k" value="2" min="1" max="20"&gt;`;
    paramsEl.querySelectorAll('input').forEach(inp =&gt; inp.addEventListener('change', () =&gt; { experiments = []; render(); }));
  }

  function sampleOne(p) {
    if (p.dist === "dice") return Math.floor(Math.random() * 6) + 1;
    if (p.dist === "binomial") { let s = 0; for (let i = 0; i &lt; p.n; i++) if (Math.random() &lt; p.p) s++; return s; }
    if (p.dist === "normal") { const u1 = Math.random(), u2 = Math.random(); return p.mu + p.sigma * Math.sqrt(-2*Math.log(u1)) * Math.cos(2*Math.PI*u2); }
    // Chi-squared: sum of k standard normals squared
    let s = 0; for (let i = 0; i &lt; p.k; i++) { const u1 = Math.random(), u2 = Math.random(); const z = Math.sqrt(-2*Math.log(u1)) * Math.cos(2*Math.PI*u2); s += z*z; } return s;
  }

  function theoreticalStats(p) {
    if (p.dist === "dice") return {mean: 3.5, sd: Math.sqrt(35/12), median: null};
    if (p.dist === "binomial") return {mean: p.n * p.p, sd: Math.sqrt(p.n * p.p * (1 - p.p)), median: null};
    if (p.dist === "normal") return {mean: p.mu, sd: p.sigma, median: null};
    return {mean: p.k, sd: Math.sqrt(2 * p.k), median: null};
  }

  function observedStats(data) {
    if (data.length === 0) return {mean: null, sd: null, median: null};
    const n = data.length;
    const mean = data.reduce((a, b) =&gt; a + b, 0) / n;
    const sd = Math.sqrt(data.reduce((a, b) =&gt; a + (b - mean) ** 2, 0) / n);
    const sorted = [...data].sort((a, b) =&gt; a - b);
    const median = n % 2 === 0 ? (sorted[n/2 - 1] + sorted[n/2]) / 2 : sorted[Math.floor(n/2)];
    return {mean, sd, median};
  }

  function binomCoeff(n, k) { if (k &lt; 0 || k &gt; n) return 0; let c = 1; for (let i = 0; i &lt; k; i++) c = c * (n - i) / (i + 1); return c; }

  function render() {
    const p = getParams();
    const theo = theoreticalStats(p);
    const obs = observedStats(experiments);
    const plotWidth = chartEl.clientWidth || 700;
    let marks = [];

    if (p.dist === "dice" || p.dist === "binomial") {
      let xs, pmf;
      if (p.dist === "dice") { xs = [1,2,3,4,5,6]; pmf = xs.map(() =&gt; 1/6); }
      else { xs = Array.from({length: p.n + 1}, (_, i) =&gt; i); pmf = xs.map(k =&gt; binomCoeff(p.n, k) * Math.pow(p.p, k) * Math.pow(1 - p.p, p.n - k)); }

      // Experiment histogram
      if (experiments.length &gt; 0) {
        const counts = {};
        experiments.forEach(v =&gt; { const r = Math.round(v); counts[r] = (counts[r] || 0) + 1; });
        const histData = Object.entries(counts).map(([x, c]) =&gt; ({x: +x, y: c / experiments.length}));
        marks.push(Plot.rectY(histData, {x1: d =&gt; d.x - 0.35, x2: d =&gt; d.x + 0.35, y1: 0, y2: "y", fill: "#CC7000", fillOpacity: 0.5}));
      }

      // PMF dots
      const pmfData = xs.map((x, i) =&gt; ({x, y: pmf[i]}));
      marks.push(Plot.dot(pmfData, {x: "x", y: "y", fill: "#333", r: 6}));
      marks.push(Plot.ruleX(pmfData, {x: "x", y1: 0, y2: "y", stroke: "#333", strokeWidth: 2}));

      // Mean line
      marks.push(Plot.ruleX([theo.mean], {stroke: "#4682B4", strokeWidth: 2.5, strokeDasharray: "6,3"}));
      if (obs.mean !== null) marks.push(Plot.ruleX([obs.mean], {stroke: "#CC7000", strokeWidth: 2.5, strokeDasharray: "6,3"}));

      marks.push(Plot.ruleY([0]));
      chartEl.innerHTML = '';
      chartEl.appendChild(Plot.plot({width: plotWidth, height: 280, marginLeft: 45,
        x: {label: "x"}, y: {label: "f", domain: [0, Math.max(...pmf) * 1.5]}, marks}));

    } else {
      let xMin, xMax, pdfFn;
      if (p.dist === "normal") { xMin = p.mu - 4*p.sigma; xMax = p.mu + 4*p.sigma; pdfFn = x =&gt; (1/(p.sigma*Math.sqrt(2*Math.PI))) * Math.exp(-0.5*((x-p.mu)/p.sigma)**2); }
      else { xMin = 0.001; xMax = Math.max(p.k * 3, 8); pdfFn = x =&gt; { if (x &lt;= 0) return 0; const k2 = p.k/2; return Math.pow(x, k2-1) * Math.exp(-x/2) / (Math.pow(2, k2) * gamma_fn(k2)); }; }

      const step = (xMax - xMin) / 200;
      const xs = Array.from({length: 201}, (_, i) =&gt; xMin + i * step);
      const pdfData = xs.map(x =&gt; ({x, y: pdfFn(x)})).filter(d =&gt; isFinite(d.y) && d.y &lt; 5);

      // Experiment histogram
      if (experiments.length &gt; 0) {
        const nBins = 25;
        const binW = (xMax - xMin) / nBins;
        const bins = new Array(nBins).fill(0);
        experiments.forEach(v =&gt; { const idx = Math.floor((v - xMin) / binW); if (idx &gt;= 0 && idx &lt; nBins) bins[idx]++; });
        const histData = bins.map((c, i) =&gt; ({x1: xMin + i*binW, x2: xMin + (i+1)*binW, y: c / (experiments.length * binW)}));
        marks.push(Plot.rectY(histData, {x1: "x1", x2: "x2", y1: 0, y2: "y", fill: "#CC7000", fillOpacity: 0.4}));
      }

      marks.push(Plot.line(pdfData, {x: "x", y: "y", stroke: "#333", strokeWidth: 2.5}));
      marks.push(Plot.ruleX([theo.mean], {stroke: "#4682B4", strokeWidth: 2.5, strokeDasharray: "6,3"}));
      if (obs.mean !== null) marks.push(Plot.ruleX([obs.mean], {stroke: "#CC7000", strokeWidth: 2.5, strokeDasharray: "6,3"}));

      marks.push(Plot.ruleY([0]));
      chartEl.innerHTML = '';
      chartEl.appendChild(Plot.plot({width: plotWidth, height: 280, marginLeft: 45,
        x: {domain: [xMin, xMax], label: "x"}, y: {label: "f"}, marks}));
    }

    // Stats display
    statsEl.innerHTML = `&lt;table&gt;
      &lt;tr&gt;&lt;td&gt;&lt;/td&gt;&lt;td class="theo"&gt;Theoretical&lt;/td&gt;&lt;td class="obs"&gt;Observed&lt;/td&gt;&lt;/tr&gt;
      &lt;tr&gt;&lt;td&gt;&lt;strong&gt;Mean:&lt;/strong&gt;&lt;/td&gt;&lt;td class="theo"&gt;${theo.mean.toFixed(2)}&lt;/td&gt;&lt;td class="obs"&gt;${obs.mean !== null ? obs.mean.toFixed(2) : '—'}&lt;/td&gt;&lt;/tr&gt;
      &lt;tr&gt;&lt;td&gt;&lt;strong&gt;St. dev.:&lt;/strong&gt;&lt;/td&gt;&lt;td class="theo"&gt;${theo.sd.toFixed(2)}&lt;/td&gt;&lt;td class="obs"&gt;${obs.sd !== null ? obs.sd.toFixed(2) : '—'}&lt;/td&gt;&lt;/tr&gt;
      &lt;tr&gt;&lt;td&gt;&lt;strong&gt;Median:&lt;/strong&gt;&lt;/td&gt;&lt;td class="theo"&gt;—&lt;/td&gt;&lt;td class="obs"&gt;${obs.median !== null ? obs.median.toFixed(2) : '—'}&lt;/td&gt;&lt;/tr&gt;
    &lt;/table&gt;`;

    infoEl.textContent = experiments.length &gt; 0 ? `Total experiments: ${experiments.length}` : '';
  }

  // Gamma function approximation (Stirling) for chi-squared PDF
  function gamma_fn(n) {
    if (n === 1) return 1;
    if (n === 0.5) return Math.sqrt(Math.PI);
    if (Number.isInteger(n)) { let f = 1; for (let i = 2; i &lt; n; i++) f *= i; return f; }
    // Half-integers
    if (Number.isInteger(n - 0.5)) { let val = Math.sqrt(Math.PI); for (let i = 0.5; i &lt; n - 0.5; i++) val *= (i + 0.5); return val; }
    // Lanczos approximation
    const g = 7; const c = [0.99999999999980993,676.5203681218851,-1259.1392167224028,771.32342877765313,-176.61502916214059,12.507343278686905,-0.13857109526572012,9.9843695780195716e-6,1.5056327351493116e-7];
    let x = c[0]; for (let i = 1; i &lt; g + 2; i++) x += c[i] / (n - 1 + i);
    const t = n - 1 + g + 0.5;
    return Math.sqrt(2 * Math.PI) * Math.pow(t, n - 0.5) * Math.exp(-t) * x;
  }

  function runExp(count) {
    const p = getParams();
    for (let i = 0; i &lt; count; i++) experiments.push(sampleOne(p));
    render();
  }

  distEl.addEventListener('change', () =&gt; { updateParamsUI(); experiments = []; render(); });
  container.querySelector('#st-1').addEventListener('click', () =&gt; runExp(1));
  container.querySelector('#st-10').addEventListener('click', () =&gt; runExp(10));
  container.querySelector('#st-50').addEventListener('click', () =&gt; runExp(50));
  container.querySelector('#st-100').addEventListener('click', () =&gt; runExp(100));
  container.querySelector('#st-refresh').addEventListener('click', () =&gt; { experiments = []; render(); });

  updateParamsUI();
  setTimeout(render, 150);
  return container;
}









