  68% completed (784 of 1145 min)

Cost Function and Gradient
The cost function (from the previous page):
\[
E(m, b) = \frac{1}{2n} \sum_{i=1}^{n} (mx_i + b - y_i)^2
\]
The partial derivatives:

def cost(m, b, X, Y):
    n = len(Y)
    return 1/(2*n) * np.sum((m*X + b - Y)**2)

def dEdm(m, b, X, Y):
    n = len(X)
    return 1/n * np.dot(m*X + b - Y, X)

def dEdb(m, b, X, Y):
    n = len(X)
    return 1/n * np.sum(m*X + b - Y)

Driving Example
Imagine you are driving your car. The horizontal axis is time (in seconds) and the vertical axis is distance (in meters). You can drag the point along the time axis below to see the connection between the function and its derivatives, first and second.

function dist(t) {
  if (t &lt;= 2) return 5 * t * t;
  if (t &lt;= 3) return 20 * t - 20;
  if (t &lt;= 7) return -5 * t * t + 50 * t - 65;
  return -20 * t + 180;
}

function vel(t) {
  if (t &lt;= 2) return 10 * t;
  if (t &lt;= 3) return 20;
  if (t &lt;= 7) return -10 * t + 50;
  return -20;
}

function acc(t) {
  if (t &lt;= 2) return 10;
  if (t &lt;= 3) return 0;
  if (t &lt;= 7) return -10;
  return 0;
}























mutable tCursor = 1







{
  const W = 700, H = 600;
  const margin = {top: 20, right: 30, bottom: 30, left: 55};
  const plotH = (H - 3 * 10) / 3;

  const svg = d3.create("svg")
    .attr("viewBox", [0, 0, W, H])
    .attr("width", W).attr("height", H)
    .style("max-width", "100%").style("cursor", "crosshair")
    .style("font-family", "'PT Sans', sans-serif");

  // Mouse tracking on the SVG (defined after xScale below)

  const tMax = 9;
  const N = 200;
  const tVals = d3.range(0, tMax + 0.01, tMax / N);

  // Scales
  const xScale = d3.scaleLinear().domain([0, tMax]).range([margin.left, W - margin.right]);

  // Now attach mouse handlers
  svg.on("mousemove", function(event) {
    const [mx] = d3.pointer(event);
    const t = xScale.invert(mx);
    if (t &gt;= 0 && t &lt;= 9) mutable tCursor = t;
  });
  svg.on("touchmove", function(event) {
    const [mx] = d3.pointer(event.touches[0], this);
    const t = xScale.invert(mx);
    if (t &gt;= 0 && t &lt;= 9) mutable tCursor = t;
    event.preventDefault();
  });

  function drawPlot(yOffset, yDomain, dataFn, label, ylabel, color) {
    const yScale = d3.scaleLinear().domain(yDomain).range([yOffset + plotH - margin.bottom, yOffset + margin.top]);

    const g = svg.append("g");

    // Grid
    g.append("rect").attr("x", margin.left).attr("y", yOffset + margin.top)
      .attr("width", W - margin.left - margin.right)
      .attr("height", plotH - margin.top - margin.bottom)
      .attr("fill", "none").attr("stroke", "#ddd").attr("stroke-width", 0.5);

    // Zero line
    if (yDomain[0] &lt; 0) {
      g.append("line")
        .attr("x1", margin.left).attr("x2", W - margin.right)
        .attr("y1", yScale(0)).attr("y2", yScale(0))
        .attr("stroke", "#4169E1").attr("stroke-width", 1.2).attr("opacity", 0.6);
    }

    // Axes
    g.append("g").attr("transform", `translate(0,${yOffset + plotH - margin.bottom})`)
      .call(d3.axisBottom(xScale).ticks(9));
    g.append("g").attr("transform", `translate(${margin.left},0)`)
      .call(d3.axisLeft(yScale).ticks(5));

    // Y-axis label
    g.append("text").attr("x", 12).attr("y", yOffset + plotH / 2)
      .attr("text-anchor", "middle").attr("font-size", "12px").attr("fill", "#333")
      .attr("transform", `rotate(-90, 12, ${yOffset + plotH / 2})`)
      .text(ylabel);

    // Plot the curve (skip for acceleration - drawn separately)
    if (label !== "a(t)") {
      const line = d3.line().x(d =&gt; xScale(d)).y(d =&gt; yScale(dataFn(d)));
      g.append("path").datum(tVals).attr("d", line)
        .attr("fill", "none").attr("stroke", "black").attr("stroke-width", 2.5);
    }

    // For acceleration: draw separate segments with open/closed circles
    if (label === "a(t)") {
      const breaks = [0, 2, 3, 7, 9];
      const vals = [10, 0, -10, 0];
      for (let i = 0; i &lt; 4; i++) {
        const t0 = breaks[i], t1 = breaks[i + 1];
        // Draw the horizontal segment (open interval, not including endpoints)
        g.append("line")
          .attr("x1", xScale(t0)).attr("y1", yScale(vals[i]))
          .attr("x2", xScale(t1)).attr("y2", yScale(vals[i]))
          .attr("stroke", "black").attr("stroke-width", 2.5);
        // Open circle at both endpoints (derivative undefined at breakpoints)
        if (i &gt; 0) {
          g.append("circle").attr("cx", xScale(t0)).attr("cy", yScale(vals[i]))
            .attr("r", 5).attr("fill", "white").attr("stroke", "black").attr("stroke-width", 1.5);
        }
        if (i &lt; 3) {
          g.append("circle").attr("cx", xScale(t1)).attr("cy", yScale(vals[i]))
            .attr("r", 5).attr("fill", "white").attr("stroke", "black").attr("stroke-width", 1.5);
        }
      }
    }

    // Current point
    const cx = xScale(tCursor);
    const cy = yScale(dataFn(tCursor));
    g.append("circle").attr("cx", cx).attr("cy", cy).attr("r", 7)
      .attr("fill", "#FF8C00").attr("stroke", "white").attr("stroke-width", 2);

    // Dashed vertical line
    g.append("line").attr("x1", cx).attr("x2", cx)
      .attr("y1", yScale(0) || yOffset + plotH - margin.bottom).attr("y2", cy)
      .attr("stroke", "#008B8B").attr("stroke-width", 1.5).attr("stroke-dasharray", "4,3");

    // Formula label based on current phase
    const t = tCursor;
    let formula = "";
    if (label === "d(t)") {
      if (t &lt;= 2) formula = "d(t) = 5t²";
      else if (t &lt;= 3) formula = "d(t) = 20t − 20";
      else if (t &lt;= 7) formula = "d(t) = −5t² + 50t − 65";
      else formula = "d(t) = −20t + 180";
    } else if (label === "v(t)") {
      if (t &lt;= 2) formula = "v(t) = d'(t) = 10t";
      else if (t &lt;= 3) formula = "v(t) = d'(t) = 20";
      else if (t &lt;= 7) formula = "v(t) = d'(t) = −10t + 50";
      else formula = "v(t) = d'(t) = −20";
    } else {
      if (t &lt;= 2) formula = "a(t) = v'(t) = 10";
      else if (t &lt;= 3) formula = "a(t) = v'(t) = 0";
      else if (t &lt;= 7) formula = "a(t) = v'(t) = −10";
      else formula = "a(t) = v'(t) = 0";
    }
    g.append("text").attr("x", cx + 12).attr("y", cy - 8)
      .attr("font-size", "13px").attr("fill", "#008B8B").attr("font-weight", "bold")
      .attr("font-style", "italic")
      .text(formula);

    // Tangent line on distance plot
    if (label === "d(t)") {
      const slope = vel(tCursor);
      const dt = 0.8;
      const x1t = tCursor - dt, x2t = tCursor + dt;
      const y1v = dataFn(tCursor) + slope * (-dt);
      const y2v = dataFn(tCursor) + slope * (dt);
      g.append("line")
        .attr("x1", xScale(Math.max(0, x1t))).attr("y1", yScale(y1v))
        .attr("x2", xScale(Math.min(tMax, x2t))).attr("y2", yScale(y2v))
        .attr("stroke", "#008B8B").attr("stroke-width", 2);
    }

    return yScale;
  }

  drawPlot(0, [-5, 65], dist, "d(t)", "d (m)", "#333");
  drawPlot(plotH + 5, [-25, 25], vel, "v(t)", "v (m/s)", "#008B8B");
  drawPlot(2 * (plotH + 5), [-25, 15], acc, "a(t)", "a (m/s²)", "#CC0066");

  return svg.node();
}






Move your mouse over the chart to explore. Notice how:

The tangent line (teal) on the distance plot shows the current slope, which equals the velocity.
When the velocity is increasing, the acceleration is positive. When velocity is decreasing, acceleration is negative. When velocity is constant, acceleration is zero.

Now let us look at each phase with the actual formulas.

Phase 1: Speeding Up (0 to 2 seconds)
You start from rest and accelerate. The distance function is:
\[d(t) = 5t^2\]
The velocity (first derivative) is \(v(t) = 10t\), which increases linearly. The acceleration (second derivative) is \(a(t) = 10\), a positive constant. You are speeding up at a constant rate.


Phase 2: Constant Speed (2 to 3 seconds)
You reach cruising speed and maintain it. The distance function is linear:
\[d(t) = 20t - 20\]
The velocity is \(v(t) = 20\) m/s (constant). The acceleration is \(a(t) = 0\). No change in speed.


Phase 3: Slowing Down and Turning Back (3 to 7 seconds)
You realize you forgot something and hit the brakes. The distance function is:
\[d(t) = -5t^2 + 50t - 65\]
The velocity is \(v(t) = -10t + 50\), which decreases linearly, crosses zero at \(t = 5\) (you stop), then goes negative (you reverse). The acceleration is \(a(t) = -10\), a negative constant. You are decelerating.
Notice: at the moment you stop (maximum distance, \(t = 5\)), \(v = 0\) and \(a &lt; 0\). The negative second derivative at a zero of the first derivative confirms this is a maximum.


Phase 4: Constant Speed in Reverse (7 to 9 seconds)
You drive back at a steady pace:
\[d(t) = -20t + 180\]
The velocity is \(v(t) = -20\) m/s (constant, negative means going back). The acceleration is \(a(t) = 0\).


